import React, { useEffect } from 'react';
import { ThemeProvider } from 'styled-components';
import { useSelector } from 'react-redux';
import { theme } from './styles/theme';
import GlobalStyles from './styles/GlobalStyles';
import Editor from './components/Editor/Editor';
import HomeScreen from './components/HomeScreen/HomeScreen';
import ErrorBoundary from './components/ErrorBoundary/ErrorBoundary';
import { migrateFromLegacy } from './utils/mapsStorage';

function App() {
  const screen = useSelector((state) => {
    return state.ui.screen;
  });
  const currentMap = useSelector((state) => {
    return state.currentMap;
  });

  useEffect(() => {
    migrateFromLegacy();
  }, []);

  useEffect(() => {
    if (screen === 'home' || currentMap.id === null) {
      document.title = 'Hex Map Tool';
    } else {
      document.title = `${currentMap.name} — Hex Map Tool`;
    }
  }, [screen, currentMap]);

  return (
    <ThemeProvider theme={theme}>
      <GlobalStyles />
      {screen === 'editor' ? (
        <ErrorBoundary>
          <Editor />
        </ErrorBoundary>
      ) : (
        <ErrorBoundary>
          <HomeScreen />
        </ErrorBoundary>
      )}
    </ThemeProvider>
  );
}

export default App;
